from dataclasses import dataclass


@dataclass(frozen=True)
class Reservation:
    tenant_id: str
    request_id: str
    sku: str
    quantity: int


class InventoryLedger:
    def __init__(self):
        self._stock: dict[tuple[str, str], int] = {}
        self._reservations: dict[str, Reservation] = {}

    def set_stock(self, tenant_id: str, sku: str, quantity: int) -> None:
        self._stock[(tenant_id, sku)] = quantity

    def stock(self, tenant_id: str, sku: str) -> int:
        return self._stock.get((tenant_id, sku), 0)

    def find(self, tenant_id: str, request_id: str) -> Reservation | None:
        return self._reservations.get(request_id)

    def reserve(
        self, tenant_id: str, request_id: str, sku: str, quantity: int
    ) -> Reservation:
        existing = self.find(tenant_id, request_id)
        if existing is not None:
            return existing
        available = self.stock(tenant_id, sku)
        if quantity <= 0 or available < quantity:
            raise ValueError("insufficient stock")
        reservation = Reservation(tenant_id, request_id, sku, quantity)
        self._stock[(tenant_id, sku)] = available - quantity
        self._reservations[request_id] = reservation
        return reservation

