from inventory.ledger import Reservation


def reservation_created(reservation: Reservation, attempt: int) -> dict[str, object]:
    return {
        "event_id": f"reservation:{reservation.request_id}:{attempt}",
        "type": "reservation.created",
        "tenant_id": reservation.tenant_id,
        "request_id": reservation.request_id,
        "sku": reservation.sku,
        "quantity": reservation.quantity,
    }


class MemoryPublisher:
    def __init__(self):
        self.messages: list[dict[str, object]] = []

    def publish(self, message: dict[str, object]) -> None:
        self.messages.append(message)
